local Gargantua_Conexoes = {}

local function AdicionarConexao(nomeDaConexao, conexao)
    if Gargantua_Conexoes[nomeDaConexao] then Gargantua_Conexoes[nomeDaConexao]:Disconnect() end
    Gargantua_Conexoes[nomeDaConexao] = conexao
end

local function RemoverConexao(nomeDaConexao)
    if Gargantua_Conexoes[nomeDaConexao] then 
        Gargantua_Conexoes[nomeDaConexao]:Disconnect()
        Gargantua_Conexoes[nomeDaConexao] = nil 
    end
end

local function LimparTodasAsConexoes()
    for nome, conexao in pairs(Gargantua_Conexoes) do
        if conexao then conexao:Disconnect() end
    end
    Gargantua_Conexoes = {} 
end

local CacheFolder = "Gargantua_HUB"
if not isfolder(CacheFolder) then pcall(function() makefolder(CacheFolder) end) end

local function GetCachedFile(filename, maxAgeInHours)
    local path = CacheFolder .. "/" .. filename
    local timePath = path .. ".timestamp"
    if isfile(path) and isfile(timePath) then
        local success, fileTimeStr = pcall(readfile, timePath)
        if success then
            local fileTime = tonumber(fileTimeStr)
            if fileTime and (os.time() - fileTime) < (maxAgeInHours * 3600) then 
                return readfile(path) 
            end
        end
    end
    return nil
end

local function SetCachedFile(filename, content)
    local path = CacheFolder .. "/" .. filename
    pcall(function() 
        writefile(path, content)
        writefile(path .. ".timestamp", tostring(os.time())) 
    end)
end

