local function VerificarBanimento()
    local hwid = "Not Supported"
    pcall(function() if gethwid then hwid = gethwid() elseif rconsoleprint and get_hwid then hwid = get_hwid() end end)
    local nomeDoJogador = LocalPlayer.Name
    pcall(function()
        local s, listaBaixada = pcall(function() return game:HttpGet(URL_DA_BLACKLIST .. "?nocache=" .. tostring(math.random(10000, 999999))) end)
        if s and listaBaixada and not string.find(listaBaixada, "404") then
            local banidoPorHWID = (hwid ~= "Not Supported" and string.find(listaBaixada, hwid, 1, true))
            local banidoPorNome = string.find(listaBaixada, nomeDoJogador, 1, true)
            if banidoPorHWID or banidoPorNome then
                local motivo = banidoPorHWID and ("HWID: " .. hwid) or ("Username: " .. nomeDoJogador)
                LocalPlayer:Kick("\n🦇 GARGANTUA SECURITY 🦇\n\nACCESS DENIED!\nYou have been permanently banned.\n\nReason: " .. motivo)
                task.wait(9e9)
            end
        end
    end)
end
