local function SwitchTheme(themeName)
    Settings.CurrentTheme = themeName; Theme = Themes[themeName]
    for themeKey, elements in pairs(ThemeElements) do for _, data in ipairs(elements) do if data.Obj and data.Obj.Parent then pcall(function() data.Obj[data.Prop] = Theme[themeKey] end) end end end
