-- 🧠 UNIVERSAL CHARACTER FINDER
-- =========================================================================
local function GetRoot(char) 
    if not char then return nil end
    return char:FindFirstChild("HumanoidRootPart") or char:FindFirstChild("Torso") or char:FindFirstChild("UpperTorso") or char.PrimaryPart 
end

local function GetHead(char) 
    if not char then return nil end
    return char:FindFirstChild("Head") or char:FindFirstChild("head") or char:FindFirstChild("HeadHitbox") or GetRoot(char) 
end

local function GetSkeletonParts(char)
    return {
        UTorso = char:FindFirstChild("UpperTorso") or char:FindFirstChild("Torso"),
        LTorso = char:FindFirstChild("LowerTorso") or char:FindFirstChild("Torso"),
        LArm = char:FindFirstChild("LeftUpperArm") or char:FindFirstChild("Left Arm"),
        LLArm = char:FindFirstChild("LeftLowerArm") or char:FindFirstChild("Left Arm"),
        LHand = char:FindFirstChild("LeftHand") or char:FindFirstChild("Left Arm"),
        RArm = char:FindFirstChild("RightUpperArm") or char:FindFirstChild("Right Arm"),
        RLArm = char:FindFirstChild("RightLowerArm") or char:FindFirstChild("Right Arm"),
        RHand = char:FindFirstChild("RightHand") or char:FindFirstChild("Right Arm"),
        LLeg = char:FindFirstChild("LeftUpperLeg") or char:FindFirstChild("Left Leg"),
        LLLeg = char:FindFirstChild("LeftLowerLeg") or char:FindFirstChild("Left Leg"),
        LFoot = char:FindFirstChild("LeftFoot") or char:FindFirstChild("Left Leg"),
        RLeg = char:FindFirstChild("RightUpperLeg") or char:FindFirstChild("Right Leg"),
        RLLeg = char:FindFirstChild("RightLowerLeg") or char:FindFirstChild("Right Leg"),
        RFoot = char:FindFirstChild("RightFoot") or char:FindFirstChild("Right Leg")
    }
end

local function GetCharacter(player)
    if player.Character and player.Character.Parent then return player.Character end
    local customFolders = {"Characters", "Live", "Players", "Entities"}
    for _, fName in ipairs(customFolders) do
        local folder = Workspace:FindFirstChild(fName)
        if folder then
            local char = folder:FindFirstChild(player.Name)
            if char and char:IsA("Model") then return char end
        end
    end
    local model = Workspace:FindFirstChild(player.Name)
    if model and model:IsA("Model") and GetRoot(model) then return model end
    return nil
end

local function IsAlive(char)
    if not char or not char.Parent then return false end
    local hum = char:FindFirstChildWhichIsA("Humanoid")
    if hum and hum.Health <= 0 then return false end
    local healthAttr = char:GetAttribute("Health")
    if type(healthAttr) == "number" and healthAttr <= 0 then return false end
    local healthVal = char:FindFirstChild("Health") or char:FindFirstChild("health")
    if healthVal and healthVal:IsA("NumberValue") and healthVal.Value <= 0 then return false end
    return true
end

local function UpdateTargetCache()
    cachedTargets = {}
    MyCharacterCache = GetCharacter(LocalPlayer)
    if not MyCharacterCache then return end

    local myTeam = LocalPlayer.Team
    for _, p in ipairs(Players:GetPlayers()) do 
        if p ~= LocalPlayer then 
            local char = GetCharacter(p)
            if char and IsAlive(char) then
                local isTeam = false
                if p.Team ~= nil and myTeam ~= nil and p.Team == myTeam then isTeam = true end
                local root = GetRoot(char)
                local head = GetHead(char)
                if root and head then
                    table.insert(cachedTargets, {Char = char, Player = p, Name = p.Name, IsTeam = isTeam, Root = root, Head = head})
                end
            end
        end 
    end

    if Settings.NpcAimbot then 
        for _, ent in ipairs(EntityCache) do 
            if ent and ent.Parent and IsAlive(ent) then 
                local ply = Players:GetPlayerFromCharacter(ent)
                local root = GetRoot(ent)
                local head = GetHead(ent)
                if root and head then
                    table.insert(cachedTargets, {Char = ent, Player = ply, Name = ply and ply.Name or ent.Name, IsTeam = false, Root = root, Head = head})
                end
            end 
        end 
    end
end

local function CreateDrawing(type, props)
    if not HasDrawing then return nil end; local success, d = pcall(function() return Drawing.new(type) end); if not success or not d then return nil end
    for k, v in pairs(props) do pcall(function() d[k] = v end) end; return d
end

local function RemoveEsp(key)
    if EspCache[key] then
        local objs = EspCache[key]
        if objs then
            if objs.Box then pcall(function() objs.Box:Remove() end) end
            if objs.Tracer then pcall(function() objs.Tracer:Remove() end) end
            if objs.Name then pcall(function() objs.Name:Remove() end) end
            if objs.Skeleton then for _, line in pairs(objs.Skeleton) do if line then pcall(function() line:Remove() end) end end end
            if objs.Cham then pcall(function() objs.Cham:Destroy() end) end 
        end
        EspCache[key] = nil
    end
end

local function CreateEspObjects(char, name)
    RemoveEsp(char)
    
    local cham = Instance.new("Highlight")
    cham.Name = "Gargantua_Cham_" .. HttpService:GenerateGUID(false)
    cham.FillTransparency = 0.5
    cham.OutlineTransparency = 0
    cham.OutlineColor = Color3.new(1, 1, 1)
    cham.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
    cham.Adornee = char
    cham.Enabled = false
    
    local targetParent = GetBestParent()
    if targetParent == Workspace.CurrentCamera then
        targetParent = char
    end
    
    pcall(function() cham.Parent = targetParent end)
    if not cham.Parent then pcall(function() cham.Parent = char end) end

    local box, tracer, nametag, bones = nil, nil, nil, nil
    if HasDrawing then
        box = CreateDrawing("Square", {Thickness = 1, Filled = false, Transparency = 1, Visible = false, Color = Color3.fromRGB(255,255,255)})
        tracer = CreateDrawing("Line", {Thickness = 1, Transparency = 1, Visible = false, Color = Color3.fromRGB(255,255,255)})
        nametag = CreateDrawing("Text", {Text = name, Size = 13, Center = true, Outline = true, Transparency = 1, Visible = false, Color = Color3.fromRGB(255,255,255), Font = Drawing.Fonts.Monospace})
        bones = {}
        for i=1, 14 do table.insert(bones, CreateDrawing("Line", {Thickness = 1.5, Transparency = 1, Visible = false, Color = Color3.fromRGB(255, 255, 255)})) end
    end
    
    EspCache[char] = {Box = box, Tracer = tracer, Name = nametag, Skeleton = bones, Cham = cham, SkelParts = GetSkeletonParts(char)}
end

local function Trigger()
    if mouse1click then mouse1click()
    elseif mouse1press and mouse1release then mouse1press(); task.wait(); mouse1release()
    else pcall(function() local myChar = MyCharacterCache; local tool = myChar and myChar:FindFirstChildOfClass("Tool"); if tool then tool:Activate() end end) end
end

local function SafeTeleport(targetCFrame)
    local char = MyCharacterCache
    if not char then return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then return end
    
    local dist = (root.Position - targetCFrame.Position).Magnitude
    if dist < 20 then
        root.CFrame = targetCFrame
        return
    end
    
    local travelTime = dist / 200 
    local tweenInfo = TweenInfo.new(travelTime, Enum.EasingStyle.Linear)
    local tween = TweenService:Create(root, tweenInfo, {CFrame = targetCFrame})
    tween:Play()
end

