local function SendCustomNotification(title, text, duration, isWarning)
    local notifFrame = Instance.new("Frame")
    notifFrame.Size = UDim2.new(0, 320, 0, 100)
    notifFrame.Position = UDim2.new(1, 350, 1, -20) 
    notifFrame.AnchorPoint = Vector2.new(1, 1)
    notifFrame.BackgroundColor3 = Theme.Background1
    notifFrame.BorderSizePixel = 0
    notifFrame.ZIndex = 100000
    notifFrame.Parent = ScreenGui
    
    local corner = Instance.new("UICorner", notifFrame)
    corner.CornerRadius = UDim.new(0, 12)
    
    local stroke = Instance.new("UIStroke", notifFrame)
    stroke.Thickness = 2
    stroke.Color = isWarning and Color3.fromRGB(255, 60, 60) or Theme.Main
    
    local titleLbl = Instance.new("TextLabel", notifFrame)
    titleLbl.Size = UDim2.new(1, -30, 0, 30)
    titleLbl.Position = UDim2.new(0, 15, 0, 10)
    titleLbl.BackgroundTransparency = 1
    titleLbl.Text = title
    titleLbl.Font = Enum.Font.Michroma
    titleLbl.TextSize = 16
    titleLbl.TextColor3 = isWarning and Color3.fromRGB(255, 60, 60) or Theme.Main
    titleLbl.TextXAlignment = Enum.TextXAlignment.Left
    titleLbl.ZIndex = 100001
    
    local textLbl = Instance.new("TextLabel", notifFrame)
    textLbl.Size = UDim2.new(1, -30, 0, 50)
    textLbl.Position = UDim2.new(0, 15, 0, 40)
    textLbl.BackgroundTransparency = 1
    textLbl.Text = text
    textLbl.Font = Enum.Font.Jura
    textLbl.TextSize = 13
    textLbl.TextColor3 = Theme.Text
    textLbl.TextXAlignment = Enum.TextXAlignment.Left
    textLbl.TextYAlignment = Enum.TextYAlignment.Top
    textLbl.TextWrapped = true
    textLbl.ZIndex = 100001
    
    local targetPos = UDim2.new(1, -20, 1, -20)
    local tweenIn = TweenService:Create(notifFrame, TweenInfo.new(0.6, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {Position = targetPos})
    tweenIn:Play()
    
    task.delay(duration, function()
        if notifFrame and notifFrame.Parent then
            local tweenOut = TweenService:Create(notifFrame, TweenInfo.new(0.6, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {Position = UDim2.new(1, 350, 1, -20)})
            tweenOut:Play()
            tweenOut.Completed:Connect(function() notifFrame:Destroy() end)
        end
    end)
end

