local TE_Sliders = {}
local function CreateRGBSlider(name, yPos, colorKey)
    local Frame = Instance.new("Frame", ThemeEditorPanel)
    Frame.Size = UDim2.new(0.9, 0, 0, 40)
    Frame.Position = UDim2.new(0.05, 0, 0, yPos)
    Frame.BackgroundTransparency = 1
    
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(1, 0, 0, 15)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.Font = Enum.Font.Jura
    Label.TextSize = 12
    Label.TextXAlignment = Enum.TextXAlignment.Left
    AddTheme(Label, "TextColor3", "Text")
    
    local Track = Instance.new("Frame", Frame)
    Track.Size = UDim2.new(1, 0, 0, 4)
    Track.Position = UDim2.new(0, 0, 0.6, 0)
    Track.BorderSizePixel = 0
    Track.BackgroundColor3 = Color3.fromRGB(40,40,40)
    AddCorner(Track, 4)
    
    local Fill = Instance.new("Frame", Track)
    Fill.Size = UDim2.new(0.5, 0, 1, 0)
    Fill.BorderSizePixel = 0 
    if colorKey == 1 then Fill.BackgroundColor3 = Color3.fromRGB(255,50,50) 
    elseif colorKey == 2 then Fill.BackgroundColor3 = Color3.fromRGB(50,255,50) 
    else Fill.BackgroundColor3 = Color3.fromRGB(50,150,255) end
    AddCorner(Fill, 4)
    
    local Grabber = Instance.new("Frame", Fill)
    Grabber.Size = UDim2.new(0, 8, 0, 16)
    Grabber.Position = UDim2.new(1, -4, 0.5, -8)
    Grabber.BorderSizePixel = 0
    Grabber.BackgroundColor3 = Color3.fromRGB(255,255,255)
    AddCorner(Grabber, 8)
    
    local Btn = Instance.new("TextButton", Track)
    Btn.Size = UDim2.new(1, 0, 1, 20)
    Btn.Position = UDim2.new(0, 0, 0.5, -10)
    Btn.BackgroundTransparency = 1
    Btn.Text = ""
    
    local function SetValue(val)
        if not Settings.CustomThemeColors then return end
        Settings.CustomThemeColors[TE_CurrentEdit][colorKey] = val
        local currentArr = Settings.CustomThemeColors[TE_CurrentEdit]
        local newColor = Color3.fromRGB(currentArr[1], currentArr[2], currentArr[3])
        Themes["Custom Theme"][TE_CurrentEdit] = newColor
        TE_Preview.BackgroundColor3 = newColor
        if Settings.CurrentTheme == "Custom Theme" then SwitchTheme("Custom Theme") end
    end
    
    local dragging = false
    Btn.InputBegan:Connect(function(input) 
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then 
            dragging = true
            local function update(inputObj) 
                local p = math.clamp((inputObj.Position.X - Track.AbsolutePosition.X) / Track.AbsoluteSize.X, 0, 1)
                Fill.Size = UDim2.new(p,0,1,0)
                SetValue(math.floor(p * 255)) 
            end
            update(input)
            local moveCon, endCon
            moveCon = UserInputService.InputChanged:Connect(function(inputObj) 
                if dragging and (inputObj.UserInputType == Enum.UserInputType.MouseMovement or inputObj.UserInputType == Enum.UserInputType.Touch) then 
                    update(inputObj) 
                end 
            end)
            endCon = UserInputService.InputEnded:Connect(function(inputObj) 
                if inputObj.UserInputType == Enum.UserInputType.MouseButton1 or inputObj.UserInputType == Enum.UserInputType.Touch then 
                    dragging = false
                    moveCon:Disconnect()
                    endCon:Disconnect() 
                end 
            end) 
        end 
    end)
    
    TE_Sliders[colorKey] = {Fill = Fill, Label = Label, BaseName = name}
end

CreateRGBSlider("RED", 135, 1)
CreateRGBSlider("GREEN", 180, 2)
CreateRGBSlider("BLUE", 225, 3)

UpdateThemeStudioSliders = function()
    if not Settings.CustomThemeColors then return end
    local currentArr = Settings.CustomThemeColors[TE_CurrentEdit]
    TE_Preview.BackgroundColor3 = Color3.fromRGB(currentArr[1], currentArr[2], currentArr[3])
    for i=1,3 do
        TE_Sliders[i].Fill.Size = UDim2.new(currentArr[i]/255, 0, 1, 0)
        TE_Sliders[i].Label.Text = TE_Sliders[i].BaseName .. " (" .. currentArr[i] .. ")"
    end
end
