local function StartParticles()
    task.spawn(function()
        while ScriptActive do
            if MainContainer.Visible and Settings.UIEffects then
                if Theme.ParticleType == "Rain" then
                    for i = 1, math.random(5, 8) do
                        local size = math.random(60, 120); local dropBox = Instance.new("Frame", RainContainer); dropBox.Size = UDim2.new(0, size, 0, size); dropBox.BackgroundColor3 = Theme.Main; dropBox.BorderSizePixel = 0; dropBox.ZIndex = 1; dropBox.Rotation = 0
                        local grad = Instance.new("UIGradient", dropBox); grad.Rotation = 22; local trans = math.random(3, 7) / 10; grad.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0.00, 1), NumberSequenceKeypoint.new(0.48, 1), NumberSequenceKeypoint.new(0.49, trans), NumberSequenceKeypoint.new(0.51, trans), NumberSequenceKeypoint.new(0.52, 1), NumberSequenceKeypoint.new(1.00, 1)})
                        local startX = math.random(-200, 760) / 620; dropBox.Position = UDim2.new(startX, 0, -0.3, 0); local speed = math.random(15, 30) / 100; local travelY = 1.4; local travelX = travelY * 420 * math.tan(math.rad(22)); local travelScaleX = travelX / 620; local endX = startX - travelScaleX; local tween = TweenService:Create(dropBox, TweenInfo.new(speed, Enum.EasingStyle.Linear), {Position = UDim2.new(endX, 0, 1.1, 0)}); tween:Play()
                        task.delay(speed * (1.1 / travelY), function() if not MainContainer.Visible or not dropBox.Parent then return end; local splash = Instance.new("Frame", RainContainer); splash.Size = UDim2.new(0, 2, 0, 2); splash.Position = UDim2.new(startX - (travelScaleX * (1.1 / travelY)), 0, 0.98, 0); splash.BackgroundColor3 = Color3.fromRGB(255, 80, 80); splash.BorderSizePixel = 0; splash.ZIndex = 1; local sTween = TweenService:Create(splash, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(0, 12, 0, 1), Position = UDim2.new(startX - (travelScaleX * (1.1 / travelY)), -6, 0.98, 0), BackgroundTransparency = 1}); sTween:Play(); sTween.Completed:Connect(function() splash:Destroy() end) end)
                        tween.Completed:Connect(function() dropBox:Destroy() end)
                    end
                    task.wait(0.05)
                elseif Theme.ParticleType == "LightSpeed" then
                    for i = 1, math.random(2, 4) do local drop = Instance.new("Frame", RainContainer); drop.Size = UDim2.new(0, math.random(60, 200), 0, math.random(1, 2)); drop.BackgroundColor3 = Theme.Main; drop.BorderSizePixel = 0; drop.Rotation = 0; drop.ZIndex = 1; local grad = Instance.new("UIGradient", drop); grad.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0.00, 1), NumberSequenceKeypoint.new(0.50, math.random(1, 5)/10), NumberSequenceKeypoint.new(1.00, 1)}); local startY = math.random(0, 100) / 100; drop.Position = UDim2.new(1.2, 0, startY, 0); local tween = TweenService:Create(drop, TweenInfo.new(math.random(40, 100) / 100, Enum.EasingStyle.Linear), {Position = UDim2.new(-0.5, 0, startY, 0)}); tween:Play(); tween.Completed:Connect(function() drop:Destroy() end) end
                    task.wait(0.08)
                elseif Theme.ParticleType == "Waterfall" then
                    for i = 1, math.random(3, 6) do local drop = Instance.new("Frame", RainContainer); drop.Size = UDim2.new(0, math.random(2, 4), 0, math.random(30, 70)); drop.BackgroundColor3 = Theme.Main; drop.BorderSizePixel = 0; drop.ZIndex = 1; local grad = Instance.new("UIGradient", drop); grad.Rotation = 90; grad.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0.00, 1), NumberSequenceKeypoint.new(0.50, math.random(2, 5)/10), NumberSequenceKeypoint.new(1.00, 1)}); local startX = math.random(0, 1000) / 1000; drop.Position = UDim2.new(startX, 0, -0.2, 0); local tween = TweenService:Create(drop, TweenInfo.new(math.random(20, 40) / 100, Enum.EasingStyle.Linear), {Position = UDim2.new(startX, 0, 1.2, 0)}); tween:Play(); tween.Completed:Connect(function() drop:Destroy() end) end
                    task.wait(0.06)
                end
            else task.wait(0.5) end
        end
    end)
end

