local function LoadSettings()
    local success, err = pcall(function()
        local path = CacheFolder .. "/" .. ConfigFileName
        if isfile(path) then
            local fileContent = readfile(path)
            local loaded = HttpService:JSONDecode(fileContent)
            for k, v in pairs(loaded) do if Settings[k] ~= nil then Settings[k] = v end end
            if isMobile then Settings.AimbotMethod = "Camera" end
            if Settings.MenuKey and Enum.KeyCode[Settings.MenuKey] then ToggleKey = Enum.KeyCode[Settings.MenuKey] end
            if not Themes[Settings.CurrentTheme] then Settings.CurrentTheme = "Atlantis (Deep Water)" end
            
            if (CurrentPlaceId == 70845479499574) and CombatTabBtn then 
                CombatTabBtn.Visible = Settings.BbnEnableCombat 
                if not Settings.BbnEnableCombat and CurrentActiveTabName == "Combat" then
                    for _, ref in ipairs(TabsRef) do ref.Page.Visible = false end
                    if BbnPage then BbnPage.Visible = true; CurrentActiveTabName = "Bite By Night" end
                end
            end
            
            SwitchTheme(Settings.CurrentTheme)
            RefreshUI()
            UpdateDetectiveVision(Settings.DetectiveVision)
        end
    end)
end

local function AttemptLogin()
    if IsAuthenticated then return end
    local inputStr = string.lower(string.gsub(KeyBox.Text or "", "^%s*(.-)%s*$", "%1"))
    if inputStr == string.lower(SECRET_KEY) then
