    SectionData.ToggleOpen = ToggleOpen; ArrowBtn.Activated:Connect(function() ToggleOpen() end); local TitleBtn = Instance.new("TextButton", SectionFrame); TitleBtn.Size = UDim2.new(1, -30, 0, 28); TitleBtn.BackgroundTransparency = 1; TitleBtn.Text = ""; TitleBtn.ZIndex = 2; TitleBtn.Activated:Connect(function() ToggleOpen() end); CLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function() if SectionData.IsOpen then SectionFrame.Size = UDim2.new(0.98, 0, 0, CLayout.AbsoluteContentSize.Y + 32) end end)
