    local function UpdateVisual() local val = Settings[settingKey]; local p = (val - min) / (max - min); Fill.Size = UDim2.new(p, 0, 1, 0); Label.Text = text .. " > " .. tostring(val) end; local dragging = false; Btn.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then dragging = true; local function update(inputObj) local p = math.clamp((inputObj.Position.X - Track.AbsolutePosition.X) / Track.AbsoluteSize.X, 0, 1); local v = max <= 1 and math.floor((min + (p * (max - min))) * 1000) / 1000 or math.floor(min + (p * (max - min))); Settings[settingKey] = v; UpdateVisual() end; update(input); local moveCon, endCon; moveCon = UserInputService.InputChanged:Connect(function(inputObj) if dragging and (inputObj.UserInputType == Enum.UserInputType.MouseMovement or inputObj.UserInputType == Enum.UserInputType.Touch) then update(inputObj) end end); endCon = UserInputService.InputEnded:Connect(function(inputObj) if inputObj.UserInputType == Enum.UserInputType.MouseButton1 or inputObj.UserInputType == Enum.UserInputType.Touch then dragging = false; moveCon:Disconnect(); endCon:Disconnect() end end) end end)
