end

local function AddKeybind(parent, text, settingKey) 
    local Frame = Instance.new("Frame", parent); Frame.Size = UDim2.new(1, -10, 0, 26); Frame.BackgroundTransparency = 1; Frame.ZIndex = 2; 
    local Label = Instance.new("TextLabel", Frame); Label.Size = UDim2.new(0.6, 0, 1, 0); Label.Position = UDim2.new(0, 10, 0, 0); Label.Text = text; Label.BackgroundTransparency = 1; Label.Font = Enum.Font.Jura; Label.TextSize = 13; Label.TextTransparency = 0; Label.TextXAlignment = Enum.TextXAlignment.Left; AddTheme(Label, "TextColor3", "Text"); 
    
    local Btn = Instance.new("TextButton", Frame); Btn.Size = UDim2.new(0, 80, 0, 18); Btn.Position = UDim2.new(1, -90, 0.5, -9); Btn.Font = Enum.Font.Michroma; Btn.TextSize = 9; Btn.BackgroundTransparency = 0; 
    AddTheme(Btn, "BackgroundColor3", "InputBg"); AddTheme(Btn, "TextColor3", "Main"); AddCorner(Btn, 6); 
    
    local function UpdateVisual() 
        local displayKey = Settings[settingKey]; 
        if displayKey == "MouseButton1" then displayKey = "MB1" 
        elseif displayKey == "MouseButton2" then displayKey = "MB2" 
        elseif displayKey == "MouseButton3" then displayKey = "MB3" end; 
        Btn.Text = "["..string.upper(displayKey).."]"; 
        if settingKey == "MenuKey" and Enum.KeyCode[Settings[settingKey]] then ToggleKey = Enum.KeyCode[Settings[settingKey]] end; 
    end; 
    local function StartBind() 
        Btn.Text = "[...]"; 
        task.delay(0.1, function() 
            local con; 
            con = UserInputService.InputBegan:Connect(function(inp) 
                local newKey = nil; 
                if inp.UserInputType == Enum.UserInputType.Keyboard then newKey = inp.KeyCode.Name 
                elseif string.find(inp.UserInputType.Name, "MouseButton") then newKey = inp.UserInputType.Name end; 
                if newKey then Settings[settingKey] = newKey; UpdateVisual(); con:Disconnect() end 
            end) 
        end) 
    end; 
    Btn.Activated:Connect(StartBind); 
    local ClickBlocker = Instance.new("TextButton", Frame); ClickBlocker.Size = UDim2.new(1, -95, 1, 0); ClickBlocker.BackgroundTransparency = 1; ClickBlocker.Text = ""; ClickBlocker.Activated:Connect(StartBind); 
    table.insert(UIUpdaters, UpdateVisual); UpdateVisual(); RegisterSearch(Frame, text) 
end

