local ColorList = {{Name = "Red", Col = Color3.fromRGB(255, 0, 0)}, {Name = "Green", Col = Color3.fromRGB(0, 255, 0)}, {Name = "Blue", Col = Color3.fromRGB(0, 100, 255)}, {Name = "Cyan", Col = Color3.fromRGB(0, 255, 255)}, {Name = "Pink", Col = Color3.fromRGB(255, 105, 180)}, {Name = "Yellow", Col = Color3.fromRGB(255, 255, 0)}, {Name = "White", Col = Color3.fromRGB(255, 255, 255)}, {Name = "Black", Col = Color3.fromRGB(0, 0, 0)}}; 
local function AddColorBtn(parent, text, isEnemy) 
    local Frame = Instance.new("Frame", parent); Frame.Size = UDim2.new(1, -10, 0, 24); Frame.BackgroundTransparency = 1; Frame.ZIndex = 2; 
    local Label = Instance.new("TextLabel", Frame); Label.Size = UDim2.new(0.6, 0, 1, 0); Label.Position = UDim2.new(0, 10, 0, 0); Label.Text = text; Label.BackgroundTransparency = 1; Label.Font = Enum.Font.Jura; Label.TextSize = 13; Label.TextXAlignment = Enum.TextXAlignment.Left; Label.ZIndex = 2; AddTheme(Label, "TextColor3", "Text"); 
    local Btn = Instance.new("TextButton", Frame); Btn.Size = UDim2.new(0, 80, 0, 18); Btn.Position = UDim2.new(1, -90, 0.5, -9); Btn.Font = Enum.Font.Jura; Btn.TextSize = 11; Btn.ZIndex = 2; AddTheme(Btn, "BackgroundColor3", "ItemBg"); AddTheme(Btn, "TextColor3", "Text"); AddCorner(Btn, 8); 
    local function UpdateVisual() local r = isEnemy and Settings.EnemyColorR or Settings.TeamColorR; local g = isEnemy and Settings.EnemyColorG or Settings.TeamColorG; local b = isEnemy and Settings.EnemyColorB or Settings.TeamColorB; local col = Color3.fromRGB(r, g, b); Btn.BackgroundColor3 = col; local name = "Custom"; for _, v in pairs(ColorList) do if v.Col == col then name = v.Name break end end; Btn.Text = string.upper(name); Btn.TextColor3 = (col.R + col.G + col.B > 1.5) and Color3.new(0,0,0) or Color3.new(1,1,1); end; 
    local function IterateColor() local idx = 1; local r = isEnemy and Settings.EnemyColorR or Settings.TeamColorR; local g = isEnemy and Settings.EnemyColorG or Settings.TeamColorG; local b = isEnemy and Settings.EnemyColorB or Settings.TeamColorB; local currentColor = Color3.fromRGB(r,g,b); for i, v in ipairs(ColorList) do if v.Col == currentColor then idx = i break end end; idx = idx + 1; if idx > #ColorList then idx = 1 end; local sel = ColorList[idx]; if isEnemy then Settings.EnemyColorR, Settings.EnemyColorG, Settings.EnemyColorB = sel.Col.R*255, sel.Col.G*255, sel.Col.B*255 else Settings.TeamColorR, Settings.TeamColorG, Settings.TeamColorB = sel.Col.R*255, sel.Col.G*255, sel.Col.B*255 end; UpdateVisual() end; 
    Btn.Activated:Connect(IterateColor); local ClickBlocker = Instance.new("TextButton", Frame); ClickBlocker.Size = UDim2.new(1, -95, 1, 0); ClickBlocker.BackgroundTransparency = 1; ClickBlocker.Text = ""; ClickBlocker.ZIndex = 5; ClickBlocker.Activated:Connect(IterateColor); table.insert(UIUpdaters, UpdateVisual); UpdateVisual(); RegisterSearch(Frame, text) 
end

