-------------------------------------------------------------------------
-- 🔄 LÓGICA DO AIMBOT E ESP - MAX FPS E RAYCAST BLINDADO
-------------------------------------------------------------------------
local tickCounter = 0
local cachedTargets = {}
local updateInterval = 0.15 
local MyCharacterCache = nil

local ScreenCenter = Vector2.new(Workspace.CurrentCamera.ViewportSize.X / 2, Workspace.CurrentCamera.ViewportSize.Y / 2)
local ScreenBottom = Vector2.new(Workspace.CurrentCamera.ViewportSize.X / 2, Workspace.CurrentCamera.ViewportSize.Y)
Workspace.CurrentCamera:GetPropertyChangedSignal("ViewportSize"):Connect(function()
    ScreenCenter = Vector2.new(Workspace.CurrentCamera.ViewportSize.X / 2, Workspace.CurrentCamera.ViewportSize.Y / 2)
    ScreenBottom = Vector2.new(Workspace.CurrentCamera.ViewportSize.X / 2, Workspace.CurrentCamera.ViewportSize.Y)
end)

local function W2S(p) 
    if not p or not p.Parent then return nil end
    local v, s = Workspace.CurrentCamera:WorldToViewportPoint(p.Position)
    return s and Vector2.new(v.X, v.Y) or nil 
end

-- 🛡️ OTIMIZAÇÃO MAX FPS: Raycast fora do loop para não fritar o executor
local SharedRaycastParams = RaycastParams.new()
SharedRaycastParams.FilterType = Enum.RaycastFilterType.Exclude
SharedRaycastParams.IgnoreWater = true

local function IsPlayerVisible(targetPart, char, camPos, checkWall, myCharOverride)
    if not checkWall then return true end
    if not targetPart or not targetPart.Parent or not char then return false end
    
    local myChar = myCharOverride or MyCharacterCache
    
    local ignoreList = {Workspace.CurrentCamera, char}
    if targetPart.Parent then table.insert(ignoreList, targetPart.Parent) end
    if myChar then table.insert(ignoreList, myChar) end
    local debris = Workspace:FindFirstChild("Debris")
    if debris then table.insert(ignoreList, debris) end
    local ignoreF = Workspace:FindFirstChild("Ignore")
    if ignoreF then table.insert(ignoreList, ignoreF) end
    
    local currentPos = camPos
    local endPos = targetPart.Position
    local dir = endPos - currentPos
    local dist = dir.Magnitude
    dir = dir.Unit
    
    local iterations = 0
    -- Raycast perfurante para ignorar vidros e zonas invisiveis (Conserta o Sticky Target)
    while iterations < 5 do
        SharedRaycastParams.FilterDescendantsInstances = ignoreList
        local result = Workspace:Raycast(currentPos, dir * dist, SharedRaycastParams)
        
        if result then
            local hitPart = result.Instance
            if hitPart.Transparency > 0.5 or not hitPart.CanCollide or hitPart.Name == "HumanoidRootPart" or hitPart.Name == "Window" or hitPart.Name == "Glass" then
                table.insert(ignoreList, hitPart)
                currentPos = result.Position + (dir * 0.01)
                dist = (endPos - currentPos).Magnitude
                iterations = iterations + 1
            else
                return false
            end
        else
            return true
        end
    end
    return false
end

local function UpdateTargetCache()
    cachedTargets = {}
    MyCharacterCache = GetCharacter(LocalPlayer)
    if not MyCharacterCache then return end

    local myTeam = LocalPlayer.Team
    for _, p in ipairs(Players:GetPlayers()) do 
        if p ~= LocalPlayer then 
            local char = GetCharacter(p)
            if char and IsAlive(char) then
                local isTeam = false
                if p.Team ~= nil and myTeam ~= nil and p.Team == myTeam then isTeam = true end
                local root = GetRoot(char)
                local head = GetHead(char)
                if root and head then
                    table.insert(cachedTargets, {Char = char, Player = p, Name = p.Name, IsTeam = isTeam, Root = root, Head = head})
                end
            end
        end 
    end

    if Settings.NpcAimbot then 
        for _, ent in ipairs(EntityCache) do 
            if ent and ent.Parent and IsAlive(ent) then 
                local ply = Players:GetPlayerFromCharacter(ent)
                local root = GetRoot(ent)
                local head = GetHead(ent)
                if root and head then
                    table.insert(cachedTargets, {Char = ent, Player = ply, Name = ply and ply.Name or ent.Name, IsTeam = false, Root = root, Head = head})
                end
            end 
        end 
    end
end

local function MainLoop(deltaTime)
    -- FIX ESP FLUTUANTE: Atualiza a câmera do jogo dinamicamente a cada frame
    Camera = Workspace.CurrentCamera
    ScreenCenter = Vector2.new(Camera.ViewportSize.X / 2, Camera.ViewportSize.Y / 2)
    ScreenBottom = Vector2.new(Camera.ViewportSize.X / 2, Camera.ViewportSize.Y)

    if not ScriptActive or not IsAuthenticated then return end
    if MainContainer.Visible then UserInputService.MouseBehavior = Enum.MouseBehavior.Default end
    
    local mouseLoc = UserInputService:GetMouseLocation()
    local camPos = Camera.CFrame.Position
    local myChar = MyCharacterCache or Camera:FindFirstChildWhichIsA("Model")
    local fovPosition = Settings.FovCenter and ScreenCenter or mouseLoc
    
    if Settings.WalkSpeedEnabled and myChar then
        local hum = myChar:FindFirstChildWhichIsA("Humanoid")
        if hum and hum:GetState() ~= Enum.HumanoidStateType.Dead then hum.WalkSpeed = Settings.WalkSpeedValue end
    end

    if not Settings.Aimbot and not Settings.EspEnabled and not Settings.MagneticHitbox and not Settings.TriggerbotNormal and not Settings.TriggerbotR2 then 
        if FOVCircle then FOVCircle.Visible = false end
        for charKey, _ in pairs(EspCache) do RemoveEsp(charKey) end
        return 
    end
    
    if HasDrawing and FOVCircle then 
        if Settings.FovEnabled then 
            if not FOVCircle.Visible then FOVCircle.Visible = true end
            FOVCircle.Radius = Settings.FovRadius
            FOVCircle.Position = fovPosition 
        else 
            if FOVCircle.Visible then FOVCircle.Visible = false end 
        end 
    end

    local isAiming = false
    if Settings.Aimbot and not UserInputService:GetFocusedTextBox() then 
        if Settings.AutoAim then isAiming = true else 
            local keyStr = Settings.AimbotKey
            if string.find(keyStr, "MouseButton") then 
                local uType = Enum.UserInputType[keyStr]
                if uType then isAiming = UserInputService:IsMouseButtonPressed(uType) end 
            else 
                local kCode = Enum.KeyCode[keyStr]
                if kCode then isAiming = UserInputService:IsKeyDown(kCode) end 
            end 
        end
    end
    
    -- FIX DO WALLCHECK COM STICKY: A Ordem é a Lei.
    if not isAiming then 
        LockedTarget = nil
        if myChar then 
            local hum = myChar:FindFirstChild("Humanoid")
            if hum then hum.AutoRotate = true end 
        end 
    elseif LockedTarget then 
        local char = LockedTarget.Parent
        local isAlive = IsAlive(char)
        local isUnderground = false
        local myRoot = GetRoot(myChar)
        local targetRoot = GetRoot(char)
        if Settings.FloorCheck and myRoot and targetRoot then 
            if targetRoot.Position.Y < (myRoot.Position.Y - 15) then isUnderground = true end 
        end
        
        local passWallcheck = true
        if Settings.AimbotWallcheck then
            passWallcheck = IsPlayerVisible(LockedTarget, char, camPos, true, myChar)
        end
        
        -- SE O CARA ESCONDER, A MIRA SOLTA NA HORA, MESMO COM O STICKY LIGADO!
        if not char or not isAlive or isUnderground or not passWallcheck then 
            LockedTarget = nil 
        end 
    end

    tickCounter = tickCounter + deltaTime
    if tickCounter >= updateInterval then 
        UpdateTargetCache()
        tickCounter = 0 
    end

    local C_Enemy = Color3.fromRGB(Settings.EnemyColorR, Settings.EnemyColorG, Settings.EnemyColorB)
    local C_Team = Color3.fromRGB(Settings.TeamColorR, Settings.TeamColorG, Settings.TeamColorB)
    
    local potentialTargets = {}
    local validTargetsList = {}
    local ActiveHighlights = 0
    local myRoot = GetRoot(myChar)

    for _, data in ipairs(cachedTargets) do
        local dist3D = (data.Head.Position - camPos).Magnitude
        if dist3D <= Settings.RenderDist then
            local headPos, vis = Camera:WorldToViewportPoint(data.Head.Position + Vector3.new(0, 0.5, 0))
            local legPos = Camera:WorldToViewportPoint(data.Root.Position - Vector3.new(0, 3, 0))
            table.insert(validTargetsList, {Data = data, Dist3D = dist3D, HeadPos = headPos, LegPos = legPos, Vis = vis})
        else 
            RemoveEsp(data.Char) 
        end
    end
    
    table.sort(validTargetsList, function(a, b) return a.Dist3D < b.Dist3D end)

    for _, vData in ipairs(validTargetsList) do
        local data = vData.Data
        local char = data.Char
        local Head = data.Head
        local RootPart = data.Root
        local dist3D = vData.Dist3D
        local headPos = vData.HeadPos
        local legPos = vData.LegPos
        local vis = vData.Vis
        
        local finalColor = C_Enemy
        if Settings.EspTeamCheck and data.IsTeam then finalColor = C_Team end
        
        local isAimbotValidTarget = true
        if Settings.AimbotTeamCheck and data.IsTeam then isAimbotValidTarget = false end
        
        local isUnderground = (Settings.FloorCheck and myRoot and RootPart.Position.Y < (myRoot.Position.Y - 15))
        
        if Settings.MagneticHitbox and isAimbotValidTarget and vis and (Settings.RageMode or ((Vector2.new(headPos.X, headPos.Y) - fovPosition).Magnitude <= Settings.FovRadius)) then 
            if not HitboxCache[char] then 
                HitboxCache[char] = Head.Size; Head.Size = Vector3.new(Settings.HitboxSize, Settings.HitboxSize, Settings.HitboxSize); Head.Transparency = 0.8; Head.CanCollide = false; Head.Massless = true 
            end 
        else 
            if HitboxCache[char] then Head.Size = HitboxCache[char]; Head.Transparency = 0; Head.CanCollide = true; Head.Massless = false; HitboxCache[char] = nil end 
        end

        local objs = EspCache[char]
        if Settings.EspEnabled and not objs then 
            CreateEspObjects(char, data.Name)
            objs = EspCache[char]
        end
        
        local showEsp2D = Settings.EspEnabled and vis and not isUnderground
        local showEsp3D = Settings.EspEnabled and not isUnderground
        if data.IsTeam and not Settings.ShowTeamEsp then 
            showEsp2D = false 
            showEsp3D = false 
        end 

        if objs and objs.Cham then
            if Settings.Chams and showEsp3D and ActiveHighlights < 25 then
                if objs.Cham.FillColor ~= finalColor then objs.Cham.FillColor = finalColor end
                if not objs.Cham.Enabled then objs.Cham.Enabled = true end
                ActiveHighlights = ActiveHighlights + 1
            else 
                if objs.Cham.Enabled then objs.Cham.Enabled = false end 
            end
        end

        if showEsp2D and objs and HasDrawing then
            local height = math.abs(headPos.Y - legPos.Y)
            local width = height / 2
            
            if Settings.Box then 
                objs.Box.Size = Vector2.new(width, height)
                objs.Box.Position = Vector2.new(headPos.X - width/2, headPos.Y)
                if objs.Box.Color ~= finalColor then objs.Box.Color = finalColor end
                if not objs.Box.Visible then objs.Box.Visible = true end
            else 
                if objs.Box.Visible then objs.Box.Visible = false end 
            end
            
            if Settings.Names then 
                objs.Name.Position = Vector2.new(headPos.X, headPos.Y - 16)
                if objs.Name.Color ~= finalColor then objs.Name.Color = finalColor end
                if not objs.Name.Visible then objs.Name.Visible = true end
            else 
                if objs.Name.Visible then objs.Name.Visible = false end
            end
            
            if Settings.Tracers then 
                objs.Tracer.From = ScreenBottom
                objs.Tracer.To = Vector2.new(headPos.X, legPos.Y)
                if objs.Tracer.Color ~= finalColor then objs.Tracer.Color = finalColor end
                if not objs.Tracer.Visible then objs.Tracer.Visible = true end 
            else 
                if objs.Tracer.Visible then objs.Tracer.Visible = false end
            end
            
            if Settings.SkeletonEsp and objs.Skeleton and dist3D < 500 then 
                local parts = objs.SkelParts
                local function DrawBone(i, p1, p2) local line = objs.Skeleton[i]; if line and p1 and p2 then if not line.Visible then line.Visible = true end; line.From = p1; line.To = p2; if line.Color ~= finalColor then line.Color = finalColor end; line.Thickness = 1.5 elseif line then if line.Visible then line.Visible = false end end end
                
                local t1 = W2S(Head); local t2 = W2S(parts.UTorso); local t3 = W2S(parts.LTorso)
                local t4 = W2S(parts.LArm); local t5 = W2S(parts.LLArm); local t6 = W2S(parts.LHand)
                local t7 = W2S(parts.RArm); local t8 = W2S(parts.RLArm); local t9 = W2S(parts.RHand)
                local t10 = W2S(parts.LLeg); local t11 = W2S(parts.LLLeg); local t12 = W2S(parts.LFoot)
                local t13 = W2S(parts.RLeg); local t14 = W2S(parts.RLLeg); local t15 = W2S(parts.RFoot)
                
                DrawBone(1, t1, t2); DrawBone(2, t2, t3); DrawBone(3, t2, t4); DrawBone(4, t4, t5); DrawBone(5, t5, t6); DrawBone(6, t2, t7); DrawBone(7, t7, t8); DrawBone(8, t8, t9); DrawBone(9, t3, t10); DrawBone(10, t10, t11); DrawBone(11, t11, t12); DrawBone(12, t3, t13); DrawBone(13, t13, t14); DrawBone(14, t14, t15) 
            else 
                if objs.Skeleton then for _, l in pairs(objs.Skeleton) do if l.Visible then l.Visible = false end end end 
            end
        else 
            if objs then 
                if objs.Box and objs.Box.Visible then objs.Box.Visible = false end; 
                if objs.Name and objs.Name.Visible then objs.Name.Visible = false end; 
                if objs.Tracer and objs.Tracer.Visible then objs.Tracer.Visible = false end; 
                if objs.Skeleton then for _, l in pairs(objs.Skeleton) do if l.Visible then l.Visible = false end end end 
            end 
        end

        if isAiming and isAimbotValidTarget and not isUnderground then 
            local magToFov = (Vector2.new(headPos.X, headPos.Y) - fovPosition).Magnitude
            if not vis then magToFov = magToFov + 10000 end 
            
            local ignoreFov = (Settings.NearestFirst and Settings.IgnoreFov)
            if Settings.RageMode or ignoreFov or (vis and magToFov <= Settings.FovRadius) then 
                table.insert(potentialTargets, {Head = Head, Char = char, DistFov = magToFov, Dist3D = dist3D}) 
            end 
        end
    end
    
    local canTrigger = (Settings.TriggerbotNormal or (Settings.TriggerbotR2 and UserInputService:IsMouseButtonPressed(Enum.UserInputType.MouseButton2))) and not IsMouseOverMenu()
    if canTrigger and not Settings.TriggerbotDebounce and (tick() - Settings.TriggerbotLastFire) >= (Settings.TriggerDelay / 1000) then 
        local bestTriggerTarget = nil
        local closestToMouse = 30
        for _, vData in ipairs(validTargetsList) do
            local data = vData.Data
            local isAimbotValidTarget = not (Settings.AimbotTeamCheck and data.IsTeam)
            local isUnderground = (Settings.FloorCheck and myRoot and data.Root.Position.Y < (myRoot.Position.Y - 15))
            if isAimbotValidTarget and not isUnderground and vData.Vis then
                local distToMouse = (Vector2.new(vData.HeadPos.X, vData.HeadPos.Y) - mouseLoc).Magnitude
                if distToMouse < closestToMouse then
                    closestToMouse = distToMouse
                    bestTriggerTarget = data
                end
            end
        end
        if bestTriggerTarget then
            if IsPlayerVisible(bestTriggerTarget.Head, bestTriggerTarget.Char, camPos, Settings.TriggerbotWallcheck, myChar) then 
                Settings.TriggerbotDebounce = true
                Trigger()
                Settings.TriggerbotLastFire = tick()
                task.spawn(function() task.wait(0.1); Settings.TriggerbotDebounce = false end) 
            end
        end
    end

    for charKey, _ in pairs(EspCache) do 
        if not charKey or not charKey.Parent or not IsAlive(charKey) then
            RemoveEsp(charKey); 
            if HitboxCache[charKey] then 
                local h = charKey:FindFirstChild("Head")
                if h then h.Size = HitboxCache[charKey] end
                HitboxCache[charKey] = nil 
            end; 
        end 
    end
    
    if isAiming then 
        local needNewTarget = true
        
        if Settings.StickyTarget and LockedTarget then
            needNewTarget = false
        end

        if needNewTarget and #potentialTargets > 0 then
            table.sort(potentialTargets, function(a, b)
                if Settings.NearestFirst then return a.Dist3D < b.Dist3D end
                return a.DistFov < b.DistFov
            end)
            
            for _, v in ipairs(potentialTargets) do 
                if not Settings.AimbotWallcheck or IsPlayerVisible(v.Head, v.Char, camPos, true, myChar) then
                    LockedTarget = v.Head 
                    break
                end
            end 
        end
    end
    
    if LockedTarget and isAiming then
        local TargetPos = LockedTarget.Position
        if Settings.Prediction > 0 then local targetRoot = GetRoot(LockedTarget.Parent); if targetRoot then local vel = targetRoot.AssemblyLinearVelocity; if vel.Magnitude > 150 then vel = vel.Unit * 150 end; TargetPos = TargetPos + (vel * Settings.Prediction) end end
        if Settings.GravityCorrection then local dist = (camPos - LockedTarget.Position).Magnitude; if dist > 100 then TargetPos = TargetPos + Vector3.new(0, (dist / 500), 0) end end
        local targetPos2D, onScreen = Camera:WorldToViewportPoint(TargetPos)
        
        local ignoreFov = (Settings.NearestFirst and Settings.IgnoreFov)
        if onScreen or Settings.RageMode or ignoreFov or Settings.StickyTarget then 
            local effSmoothness = Settings.AimbotSmoothness
            if Settings.AimbotMethod == "Mouse" and onScreen then 
                local aimOrigin = Settings.FovCenter and ScreenCenter or mouseLoc
                local moveX = (targetPos2D.X - aimOrigin.X); local moveY = (targetPos2D.Y - aimOrigin.Y)
                if mousemoverel then 
                    local baseDamp = 2.5
                    if effSmoothness <= 0 then pcall(function() mousemoverel(moveX / baseDamp, moveY / baseDamp) end) else local sm = math.max(1, effSmoothness) * baseDamp; pcall(function() mousemoverel(moveX / sm, moveY / sm) end) end 
                else 
                    Camera.CFrame = Camera.CFrame:Lerp(CFrame.lookAt(camPos, TargetPos), 1 / ((effSmoothness / 2) + 2)) 
                end 
            elseif Settings.AimbotMethod == "Camera" or not onScreen then 
                local targetCFrame = CFrame.lookAt(camPos, TargetPos)
                if effSmoothness <= 0 then Camera.CFrame = targetCFrame else Camera.CFrame = Camera.CFrame:Lerp(targetCFrame, 1 / ((effSmoothness / 2) + 1)) end 
            end 
        end
    end
end

RunService:BindToRenderStep("Gargantua_MainLoop", Enum.RenderPriority.Camera.Value + 200, MainLoop)
local InputLoopConnection = UserInputService.InputBegan:Connect(function(i,p) if not p and i.KeyCode == ToggleKey then ToggleUI() end end)

local UnsupportedGames = {[72920620366355] = true, [114234929420007] = true, [292439477] = true, [17516596118] = true, [100040622766961] = true}

if UnsupportedGames[CurrentPlaceId] then 
    SendCustomNotification("GARGANTUA HUB [WARNING]", "Game not officially supported. Use at your own risk!\n(ID: " .. tostring(CurrentPlaceId) .. ")", 10, true) 
else 
    SendCustomNotification("GARGANTUA HUB", "Successfully loaded!\n(Current Map ID: " .. tostring(CurrentPlaceId) .. ")", 6, false) 
end

if _G.Gargantua_Unload then pcall(_G.Gargantua_Unload) end

_G.Gargantua_Unload = function()
    ScriptActive = false; UpdateDetectiveVision(false); RunService:UnbindFromRenderStep("Gargantua_MainLoop"); if InputLoopConnection then InputLoopConnection:Disconnect() end; if FOVCircle then FOVCircle.Visible = false; pcall(function() FOVCircle:Remove() end) end; if ScreenGui and ScreenGui.Parent then ScreenGui.Enabled = false; Debris:AddItem(ScreenGui, 1) end; if LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("Humanoid") then LocalPlayer.Character.Humanoid.AutoRotate = true end; for charKey, objs in pairs(EspCache) do RemoveEsp(charKey) end; EspCache = {}; HitboxCache = {}; MapCache = {}; _G.GargantuaHub_Ran = nil; _G.Gargantua_Unload = nil
    local safePart = Workspace:FindFirstChild("Gargantua_BbnSafePart"); if safePart then safePart:Destroy() end
    LimparTodasAsConexoes()
end

-- APENAS AS FUNÇÕES DOS TEMAS
local function ApplyCustomTheme()
    SwitchTheme("Custom Theme")
end

UpdateNeonVisibility()
RefreshUI()

